def build_retina(m,s):
 sid=m["source_id"];t=base(m,"Four uniform and two patterned VACNT preparations separated by Al underlayer, oxygen-plasma treatment and pattern/growth time.")
 recs=(("FE","Fe only",False,False,"5","uniform 30-38 micrometre forest; prone to cracking/delamination"),("ALFE","Al/Fe",True,False,"5","uniform 30-38 micrometre forest; mechanically stable; best neurite outgrowth"),("FE_PL","Fe only + oxygen plasma",False,True,"5","uniform 30-38 micrometre plasma-functionalized forest; cracking/delamination"),("ALFE_PL","Al/Fe + oxygen plasma",True,True,"5","stable uniform forest but plasma reduced neurite outgrowth versus untreated Al/Fe"),("ALFE_PAT100","Al/Fe patterned 100 micrometre rows",True,False,"3","21-31 micrometre tall rows; supported retinal neurite growth through 7 DIV"),("ALFE_PAT2P5","Al/Fe high-aspect pattern",True,False,"3","2.5 micrometre row width, 10 micrometre spacing and 20 micrometre height"))
 for code,label,al,pl,mins,out in recs:
  rid=f"{sid}_{code}";t["source_run"].append(run_row(sid,code,label,out))
  t["catalyst_system"].append(catalyst_row(rid,catalyst_label=("4-8 nm Al / " if al else "")+"6-12 nm Fe on 300 nm SiO2/Si",active_metals="Fe",support_material=("Al underlayer on " if al else "")+"300 nm thermal SiO2/Si",metal_ratio_original="Al 4-8 nm; Fe 6-12 nm" if al else "Fe 6-12 nm",preparation_method="thermal evaporation over full chip" if "PAT" not in code else "photolithographic patterning and thermal evaporation",post_preparation_condition="O2 plasma 300 mTorr, 5 min, 50 W" if pl else "no plasma"))
  t["reactor_process_gas"].append(process_row(rid,1,"atmospheric_CVD",reactor_type="2-inch quartz tube",temperature_setpoint_C="650",holding_time_min=mins,carbon_source="C2H4",carbon_source_flow_original="200 sccm",carbon_source_flow_sccm="200",reducing_gas="H2",reducing_gas_flow_original="100 sccm",reducing_gas_flow_sccm="100",inert_gas="Ar",inert_gas_flow_original="600 sccm",inert_gas_flow_sccm="600",total_flow_original="900 sccm",total_flow_sccm="900",gas_composition_summary="C2H4/H2 2:1 plus Ar"))
  t["yield_quality"].append(yield_row(rid,primary_yield_metric="VACNT morphology/mechanical integrity",yield_original=out,yield_definition_original="SEM/TEM and retinal-culture outcome; no mass yield.",secondary_result_summary=out,CNT_type_reported="vertically aligned carbon nanotubes",CNT_type_confirmed="MWCNT",product_mixture_summary="VACNT forest",CNT_type_evidence="TEM shows multi-walled CNT; SEM/Raman/XPS",length_summary="30-38 micrometres" if mins=="5" else "21-31 micrometres" if code=="ALFE_PAT100" else "20 micrometres",morphology="dense vertical forest",alignment_or_array="vertically aligned forest",characterization_methods="SEM; TEM; Raman 532 nm; XPS; contact angle; retinal-cell culture"))
