 t["review_issue_log"].append(issue_row(f"{sid}_ISSUE_GROWTH",sid,f"{sid}_GO_MWNT","source_scope","source_run",f"{sid}_GO_MWNT","data_type","MWCNTs were purchased; all rows are source-specific post-processing/sensor fabrication, not CNT growth.",f"EVD_{sid}_GO_MWNT_CAT","high"));return t
