  t["catalyst_system"].append(catalyst_row(rid,catalyst_label="1.5 nm Fe / 40 nm Al2O3",active_metals="Fe",support_material="40 nm sputtered Al2O3",metal_ratio_original="Al2O3 40 nm / Fe 1.5 nm",preparation_method="sequential sputtering",activation_condition="He/H2 1:9 at 750 C"))
  t["reactor_process_gas"].append(process_row(rid,1,"water_assisted_CVD_optimization",reactor_type="fully automated CVD system with exchange chamber",temperature_setpoint_C="725-900 optimized",holding_time_min="10",carbon_source=feed,carbon_source_flow_original="feed-specific optimized; <100 sccm typical and lowered for highly reactive feeds",inert_gas="He",total_flow_original="1 L/min",total_flow_sccm="1000",cofeed_or_reactive_gas="water 50-500 ppm optimized",gas_composition_summary=f"{feed} ({cls}) + water enhancer in He"))
  t["yield_quality"].append(yield_row(rid,primary_yield_metric="SWCNT forest formation/height",yield_original=out,yield_definition_original="Optimized forest height; exact feed/temperature/water optimum is figure/table-specific and not reproduced in parsed text.",secondary_result_summary="Average diameter across successful feeds 2.5-3.1 nm; density 0.028-0.046 g/cm3; acetylene highest reactivity/lowest required input.",CNT_type_reported="single-wall carbon nanotube forest",CNT_type_confirmed="SWCNT forest" if code!="CH4" else "not_applicable",product_mixture_summary=out,CNT_type_evidence="SEM/TEM/FTIR/Raman",outer_diameter_range_nm="average 2.5-3.1; distributions ~1 to >4",morphology="vertical forest" if code!="CH4" else "no forest",alignment_or_array="vertically aligned forest",characterization_methods="SEM; TEM; FTIR; Raman; gravimetric density"))
