def build_refractory(m,s):
 sid=m["source_id"];t=base(m,"Four core pure/mixed-metal thin-film catalyst comparisons under one optimized ethylene CVD recipe.")
 recs=(("FE5","0.5 nm Fe","Fe","0.5 nm Fe","CNTs reach about 400 micrometres in 4-5 min; 80-100 micrometres/min"),("FE10","1.0 nm Fe","Fe","1.0 nm Fe","CNT growth about 15 min; ultimate length about 800 micrometres; mixed SWCNT/MWCNT with MWCNT dominance"),("FE5W5","0.5 nm Fe + 0.5 nm W","Fe; W","1:1 thickness ratio","CNTs about 950 micrometres at 30 min (~32 micrometres/min); longer lifetime; MWCNT, IG/ID ~0.66"),("FE5OS5","0.5 nm Fe + 0.5 nm Os","Fe; Os","1:1 thickness ratio","dense MWCNT mat; reduced particle coarsening/stabilization relative to pure Fe"))
 for code,label,metals,ratio,out in recs:
  rid=f"{sid}_{code}";t["source_run"].append(run_row(sid,code,label,out))
  t["catalyst_system"].append(catalyst_row(rid,catalyst_label=label+" on Al2O3/SiO2/Si",active_metals=metals,support_material="15-30 nm Al2O3 on 1 micrometre SiO2/Si",metal_ratio_original=ratio,precursor_summary="Fe(acac)3; W(CO)6 or osmocene/osmium carbonyl; polystyrene in toluene",preparation_method="spin-on organometallic/polymer film then O2 RF plasma",preparation_detail="Typical 5-10 mM organometallics + 30 g/L polystyrene spun at 4000 rpm; plasma removes ligands/polymer leaving metal oxides.",reduction_condition="Ar/H2 at 750 C, 15 min",phase_or_state_summary="nanometre catalyst particles; refractory mixed metal stabilizes Fe"))
  t["reactor_process_gas"].append(process_row(rid,1,"thermal_CVD",reactor_type="1-inch-ID, 24-inch quartz-tube furnace",temperature_setpoint_C="750",holding_time_min="2-60; key comparison up to 30",pressure_original="1 atm",pressure_kPa="101.325",carbon_source="C2H4",carbon_source_flow_original="25 sccm",carbon_source_flow_sccm="25",reducing_gas="H2",reducing_gas_flow_original="25 sccm",reducing_gas_flow_sccm="25",inert_gas="Ar",inert_gas_flow_original="100 sccm",inert_gas_flow_sccm="100",total_flow_original="150 sccm",total_flow_sccm="150",gas_composition_summary="15 min Ar/H2 anneal then ethylene added"))
  t["yield_quality"].append(yield_row(rid,primary_yield_metric="CNT mat growth lifetime/ultimate length",yield_original=out,yield_definition_original="SEM length-versus-time; no mass yield.",secondary_result_summary=out,CNT_type_reported="carbon nanotubes",CNT_type_confirmed="MWCNT-dominant",product_mixture_summary="dense vertically aligned CNT mat",CNT_type_evidence="SEM/TEM/Raman/EDS",length_summary=out,morphology="dense aligned CNT mat",alignment_or_array="vertically aligned",Raman_ratio_type="IG/ID",Raman_ratio_value="~0.66" if code=="FE5W5" else "1-2 near top for Fe10" if code=="FE10" else "not_reported",characterization_methods="SEM; TEM; micro-Raman; AFM; EDS"))
  t["cost_scale_review"].append(cost_row(rid,scale_evidence_summary="Laboratory multi-coupon CVD; up to 12 catalyst compositions per run.",cost_driver_summary="Al2O3 barrier, spin-on Fe/refractory organometallics, plasma, 750 C ethylene/H2 CVD.",safety_risk="Ethylene/hydrogen at 750 C; toxic/valuable Os or W organometallics and toluene.",emission_or_waste="CVD exhaust, organometallic/polymer waste and refractory-metal CNT substrates."));ev(t,s,sid,rid,"SPAN_08259FBDAAB6CC05CF66","SPAN_2544EFE7A69217AB221F","SPAN_0740389C22B1A6F1AC30" if code=="FE5W5" else "SPAN_0230087EB9A41D76F890")
 return t
BUILDERS:dict[str,Callable]={"LIT_7DB638A390C20E74":build_retina,"LIT_85779E66B8B0D55E":build_sensor,"LIT_87B8240D8CDFE77C":build_feedstocks,"LIT_9181CCCE7A19C985":build_filled,"LIT_91BE111AC6247FA8":build_refractory}
